import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import "./blog.css";
import backgroundImage from "../../images/blogimages/blogBackground.jpg";

const API_BASE_URL = 'https://e-nutritionist-b1d035f17120.herokuapp.com/'; 

const Blogs = () => {
  const [blogs, setBlogs] = useState([]);

  useEffect(() => {
    fetch(`${API_BASE_URL}/blogs`) 
      .then(response => response.json())
      .then(data => setBlogs(data));
  }, []);

  return (
    <div className='blogs'>
      <h1 className='title'>Blogs</h1>
      <ul className='blog-container'>
        {blogs.map(blog => (
          <li key={blog.id} className='blog'>
            <img src={`${API_BASE_URL}${blog.img_urls}`} alt="test" className='blog-image'/>
            <h2 className='blog-title'>{blog.title}</h2>
            <p className='blog-description'>{blog.description}</p>
            <Link to={`/blogs/${blog.id}`} className='blog-a'>Read More</Link>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default Blogs;
